func TestGetForecast(t *testing.T) {
	forecast, err := GetForecast("48", "11", time.Now())
	assert.NoError(t, err)
	assert.NotEmpty(t, forecast.Icon)
}

func TestParseForecast(t *testing.T) {
	forecast, err := parseForecast([]byte(testResponse), "2026-06-11")
	assert.NoError(t, err)
	assert.Equal(t, "partly-cloudy", forecast.Icon)
	assert.Equal(t, 15, forecast.High)
	assert.Equal(t, 7, forecast.Low)
	assert.Equal(t, 34, forecast.PrecipitationProbability)
	assert.Equal(t, 0.0, forecast.PrecipitationAmount)
}
